import{_ as a,o as i,c as t,a2 as r}from"./chunks/framework.C7GIOALF.js";const m=JSON.parse('{"title":"HordeMagic.com EDH-Style Variant","description":"","frontmatter":{},"headers":[],"relativePath":"formats/horde/sources/hordemagic-com.md","filePath":"formats/horde/sources/hordemagic-com.md","lastUpdated":1782025909000}'),l={name:"formats/horde/sources/hordemagic-com.md"};function o(n,e,s,h,d,c){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="hordemagic-com-edh-style-variant" tabindex="-1">HordeMagic.com EDH-Style Variant <a class="header-anchor" href="#hordemagic-com-edh-style-variant" aria-label="Permalink to &quot;HordeMagic.com EDH-Style Variant&quot;">​</a></h1><p>Source: <a href="https://hordemagic.com/" target="_blank" rel="noreferrer">https://hordemagic.com/</a></p><p>This source presents a modern EDH-style Horde Magic variant inspired by Peter Knudson&#39;s original Horde Magic rules.</p><h2 id="related-source-links" tabindex="-1">Related Source Links <a class="header-anchor" href="#related-source-links" aria-label="Permalink to &quot;Related Source Links&quot;">​</a></h2><ul><li>Original Horde Magic article: <a href="https://www.quietspeculation.com/2011/09/horde-magic-a-new-way-to-play-magic-and-survive-zombie-invasions/" target="_blank" rel="noreferrer">https://www.quietspeculation.com/2011/09/horde-magic-a-new-way-to-play-magic-and-survive-zombie-invasions/</a></li><li>Horde Magic follow-up: <a href="https://www.quietspeculation.com/2011/10/horde-magic-an-open-source-project/" target="_blank" rel="noreferrer">https://www.quietspeculation.com/2011/10/horde-magic-an-open-source-project/</a></li><li>MTG Wiki rules summary: <a href="https://mtg.fandom.com/wiki/Horde_Magic#Rules_for_The_Horde" target="_blank" rel="noreferrer">https://mtg.fandom.com/wiki/Horde_Magic#Rules_for_The_Horde</a></li></ul><h2 id="premise" tabindex="-1">Premise <a class="header-anchor" href="#premise" aria-label="Permalink to &quot;Premise&quot;">​</a></h2><p>Horde Magic is a cooperative Magic format where one to four players fight an automated enemy deck. This version assumes players use EDH decks against a large Horde library.</p><h2 id="player-setup" tabindex="-1">Player Setup <a class="header-anchor" href="#player-setup" aria-label="Permalink to &quot;Player Setup&quot;">​</a></h2><ul><li>Each player chooses an EDH deck.</li><li>Players take three setup turns before the Horde takes its first turn, unless the scenario says otherwise.</li><li>The setup turns let players establish a minimal board before the Horde begins producing waves.</li></ul><h2 id="horde-gameplay" tabindex="-1">Horde Gameplay <a class="header-anchor" href="#horde-gameplay" aria-label="Permalink to &quot;Horde Gameplay&quot;">​</a></h2><ul><li>The Horde has a roughly 300-card library.</li><li>The Horde has infinite mana for casting costs and activation costs.</li><li>The Horde casts spells in <strong>waves</strong>.</li><li>Cards are cast from the top of the Horde library until the wave ends.</li><li>The Horde does not have a hand.</li><li>If the Horde would draw a card, it puts that card directly into play instead.</li><li>If a Horde-owned permanent would return to the Horde&#39;s hand, put it on top of the Horde library instead.</li><li>If the Horde is instructed to discard, it may put the top card of its library into its graveyard.</li></ul><h2 id="creature-rules" tabindex="-1">Creature Rules <a class="header-anchor" href="#creature-rules" aria-label="Permalink to &quot;Creature Rules&quot;">​</a></h2><ul><li>Horde creatures have haste.</li><li>Horde creatures are goaded unless otherwise stated.</li><li>Only Horde creatures with defender can block.</li><li>Card-triggered abilities happen immediately.</li><li>Activated abilities follow summoning sickness.</li><li>Activated abilities happen during the post-combat main phase.</li><li>A permanent with an activated ability can activate that ability only once per turn.</li></ul><h2 id="waves" tabindex="-1">Waves <a class="header-anchor" href="#waves" aria-label="Permalink to &quot;Waves&quot;">​</a></h2><ul><li>The Horde plays one wave per turn by default.</li><li>Optional: Increase wave count based on the number of players.</li><li>Optional: Use a repeating wave count pattern such as <code>1, 2, 3, 2, 1, 2, 3, 2, 1</code>.</li><li>Waves end when an uncommon, rare, or mythic card enters the battlefield.</li></ul><h2 id="player-team-rules" tabindex="-1">Player Team Rules <a class="header-anchor" href="#player-team-rules" aria-label="Permalink to &quot;Player Team Rules&quot;">​</a></h2><ul><li>One to four human players can battle the Horde.</li><li>Human players act as a single team, taking turns and phases in unison.</li><li>The Horde is also treated as a player.</li><li>Player life totals are combined.</li></ul><h2 id="starting-life" tabindex="-1">Starting Life <a class="header-anchor" href="#starting-life" aria-label="Permalink to &quot;Starting Life&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Players</th><th style="text-align:right;">Shared Life Total</th></tr></thead><tbody><tr><td>1</td><td style="text-align:right;">100</td></tr><tr><td>2</td><td style="text-align:right;">85</td></tr><tr><td>3</td><td style="text-align:right;">70</td></tr></tbody></table><p>Each player beyond the first reduces the starting shared life total by 15.</p><h2 id="damage-and-life" tabindex="-1">Damage And Life <a class="header-anchor" href="#damage-and-life" aria-label="Permalink to &quot;Damage And Life&quot;">​</a></h2><ul><li>Damage dealt to the Horde mills that many cards from the Horde library.</li><li>Optional recommended rule: If a legendary creature is milled this way, it enters the battlefield and then phases out instead.</li><li>Lifegain for the Horde has no effect.</li><li>Optional: Horde lifegain may put cards from the Horde graveyard on the bottom of the Horde library.</li><li>Damage dealt to the players reduces the shared life total.</li><li>Lifegain by the players increases the shared life total.</li></ul><h2 id="each-player-and-each-opponent" tabindex="-1">&quot;Each Player&quot; And &quot;Each Opponent&quot; <a class="header-anchor" href="#each-player-and-each-opponent" aria-label="Permalink to &quot;&quot;Each Player&quot; And &quot;Each Opponent&quot;&quot;">​</a></h2><ul><li>Effects that refer to <strong>each player</strong> trigger for each player.</li><li>Effects that refer to <strong>each opponent</strong> trigger only once.</li></ul><h2 id="horde-decisions" tabindex="-1">Horde Decisions <a class="header-anchor" href="#horde-decisions" aria-label="Permalink to &quot;Horde Decisions&quot;">​</a></h2><p>When the Horde must make a decision, make the decision in the Horde&#39;s best interest. The source emphasizes honesty: the challenge is the fun.</p><h2 id="win-conditions" tabindex="-1">Win Conditions <a class="header-anchor" href="#win-conditions" aria-label="Permalink to &quot;Win Conditions&quot;">​</a></h2><p>The players win if:</p><ul><li>The Horde library is empty.</li><li>The Horde battlefield is empty.</li></ul><p>The Horde wins if:</p><ul><li>The players have no life.</li><li>The players have no cards to draw.</li><li>The players reach the poison limit.</li></ul><p>Cards with alternate win conditions, such as &quot;you win the game&quot; text, are not legal.</p><h2 id="ban-philosophy" tabindex="-1">Ban Philosophy <a class="header-anchor" href="#ban-philosophy" aria-label="Permalink to &quot;Ban Philosophy&quot;">​</a></h2><p>The ban list is meant to prevent cards that make the Horde nonfunctional or mathematically trivial to beat. Permanents with one-shot effects are more acceptable than static effects that permanently shut down the Horde.</p><p>Cards are suspect if they:</p><ul><li>Make Horde creatures enter tapped.</li><li>Kill Horde creatures as they enter.</li><li>Mill the Horde on enter-the-battlefield or graveyard triggers.</li><li>Gain life based on the cumulative power of attacks.</li><li>Make the matchup mathematically too easy.</li></ul><h2 id="banned-combos" tabindex="-1">Banned Combos <a class="header-anchor" href="#banned-combos" aria-label="Permalink to &quot;Banned Combos&quot;">​</a></h2><ul><li>Midnight Guard + Elemental Mastery</li><li>Exquisite Blood + Sanguine Bond</li></ul><h2 id="current-ban-list" tabindex="-1">Current Ban List <a class="header-anchor" href="#current-ban-list" aria-label="Permalink to &quot;Current Ban List&quot;">​</a></h2><h3 id="creatures" tabindex="-1">Creatures <a class="header-anchor" href="#creatures" aria-label="Permalink to &quot;Creatures&quot;">​</a></h3><ul><li>Elesh Norn, Grand Cenobite</li><li>Magus of the Moat</li><li>Massacre Wurm</li><li>Plague Engineer</li><li>Platinum Angel</li><li>Platinum Emperion</li><li>Rampaging Ferocidon</li><li>Silent Arbiter</li><li>Stormtide Leviathan</li><li>Urabrask the Hidden</li></ul><h3 id="enchantments" tabindex="-1">Enchantments <a class="header-anchor" href="#enchantments" aria-label="Permalink to &quot;Enchantments&quot;">​</a></h3><ul><li>Aether Flash</li><li>Aurification</li><li>Authority of the Consuls</li><li>Barbed Foliage</li><li>Blind Obedience</li><li>Dueling Grounds</li><li>Island Sanctuary</li><li>Lethal Vapors</li><li>Leyline of Singularity</li><li>No Mercy</li><li>Pyrohemia</li><li>Rest in Peace</li><li>Solitary Confinement</li><li>Tainted Aether</li><li>Teferi&#39;s Moat</li></ul><h3 id="instants" tabindex="-1">Instants <a class="header-anchor" href="#instants" aria-label="Permalink to &quot;Instants&quot;">​</a></h3><ul><li>Surgical Extraction</li></ul><h3 id="sorceries" tabindex="-1">Sorceries <a class="header-anchor" href="#sorceries" aria-label="Permalink to &quot;Sorceries&quot;">​</a></h3><ul><li>Eradicate</li><li>Haunting Echoes</li><li>Mind Funeral</li><li>Time Stretch</li></ul><h3 id="artifacts" tabindex="-1">Artifacts <a class="header-anchor" href="#artifacts" aria-label="Permalink to &quot;Artifacts&quot;">​</a></h3><ul><li>Caltrops</li><li>Crawlspace</li><li>Ensnaring Bridge</li><li>Grindstone</li><li>Platinum Angel</li><li>Platinum Emperion</li><li>Quietus Spike</li><li>Silent Arbiter</li><li>Trepanation Blade</li></ul>',49)])])}const p=a(l,[["render",o]]);export{m as __pageData,p as default};
